        q: '={{$json.query}}',
        location: 'United States',
        num: 10
      }
    }
  ],
  memory: {
    type: 'windowBuffer',
    maxTokens: 4000
  },
  outputParser: 'json'
};

// Node: Search Agent
const searchAgent = {
  agent: 'research',
  tools: [{ type: 'serpapi', name: 'search' }]
};

// Node: Analyze Agent (receives search results)
const analyzeAgent = {
  systemMessage: 'Analyze these search results for claim accuracy: {{$node["Search Agent"].json}}',
  tools: [{ type: 'code', name: 'analyze_claims' }]
};

// Node: Synthesize Agent
const synthAgent = {
  systemMessage: 'Synthesize final report from analysis: {{$node["Analyze Agent"].json}}'
};

const vexWebhook = {
  method: 'POST',
  url: 'https://api.vex.dev/v1/verify',
  headers: {
    'Authorization': 'Bearer {{ $env.VEX_API_KEY }}',
    'Content-Type': 'application/json'
  },
  body: {
    sessionId: '={{ $json.sessionId }}',
    input: '={{ $json.userQuery }}',
    output: '={{ $json.agentOutput }}',
    useCase: 'research-agent',
    checks: ['source_verification', 'claim_accuracy', 'recency', 'bias_detection']
  }
};

const researchTools = [
  {
    type: 'serpapi',
    name: 'web_search',
    condition: "query.includes('latest') || query.includes('recent')"
  },
  {
    type: 'httpRequest',
    name: 'scrape_page',
    condition: "query.includes('specific URL')",
    parameters: {
      url: '={{ $json.targetUrl }}'
    }
  }
];

const agent = {
  tools: researchTools.filter(tool => eval(tool.condition))
};

