import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'n8n-research-agent'
});

const result = await vex.verify({
  sessionId: workflow.data.sessionId,
  input: workflow.data.query,
  output: workflow.data.searchResults,
  checks: {
    sourceVerification: {
      requireHttps: true,
      maxAgeDays: 30,
      domainsAllowlist: ['.edu', '.gov', '.org']
    }
  }
});

if (!result.pass) {
  throw new Error(`Source verification failed: ${result.issues}`);
}

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

const verification = await vex.verify({
  sessionId: `research-${Date.now()}`,
  input: 'Analyze: ' + analysisInput,
  output: agentAnalysis,
  checks: {
    claimAccuracy: {
      evidenceRequired: true,
      minConfidence: 0.8
    },
    biasDetection: {
      politicalBias: 'neutral',
      sensationalism: 'low'
    }
  }
});

workflow.data.vexScore = verification.score;
if (verification.score < 0.75) {
  workflow.data.flagged = true;
}

import { Vex } from '@vex_dev/sdk';

const client = new Vex({
  apiKey: n8n.workflow.staticData.vexKey
});

const guardrailResult = await client.verify({
  sessionId: $input.first().json.sessionId,
  input: $input.first().json.query,
  output: $input.first().json.synthesis,
  checks: {
    recursionDetection: {
      maxIterations: 5,
      selfTriggerBlock: true
    },
    recencyCheck: {
      maxAgeHours: 24,
      timeSensitive: $input.first().json.query.includes('latest')
    },
    piiRedaction: 'strict'
  }
});

return {
  verified: guardrailResult.pass,
  score: guardrailResult.score,
  issues: guardrailResult.issues
};
